import { CurrencyPipe } from '@angular/common';
import { Component, Input } from '@angular/core';
import { Artwork } from '../../interfaces/artwork.interface';
import { SiteLanguage } from '../../interfaces/language.interface';

@Component({
  selector: 'app-artwork-info',
  standalone: true,
  imports: [CurrencyPipe],
  templateUrl: './artwork-info.component.html',
  styleUrl: './artwork-info.component.sass'
})
export class ArtworkInfoComponent {
  @Input({ required: true }) artwork!: Artwork;
  @Input({ required: true }) language!: SiteLanguage;
  @Input({ required: true }) artistEmail!: string;
  @Input() layout: 'default' | 'product' = 'default';

  protected get statusLabel(): string {
    const labels = {
      it: {
        available: 'Disponibile',
        sold: 'Venduta',
        reserved: 'Riservata',
        private_collection: 'Collezione privata',
        not_available: 'Non disponibile'
      },
      en: {
        available: 'Available',
        sold: 'Sold',
        reserved: 'Reserved',
        private_collection: 'Private Collection',
        not_available: 'Not Available'
      }
    };

    return labels[this.language][this.artwork.status];
  }

  protected get shouldShowDescription(): boolean {
    return this.artwork.texts.visibleMode === 'description' || this.artwork.texts.visibleMode === 'both';
  }

  protected get shouldShowPoetic(): boolean {
    return this.artwork.texts.visibleMode === 'poetic' || this.artwork.texts.visibleMode === 'both';
  }

  protected get shouldShowPrice(): boolean {
    return this.artwork.price.amount !== null;
  }

  protected get isUnavailable(): boolean {
    return this.artwork.status === 'sold' || this.artwork.status === 'private_collection' || this.artwork.status === 'not_available';
  }

  protected get mailtoLink(): string {
    const title = this.language === 'it' ? this.artwork.title.it : this.artwork.title.en || this.artwork.title.it;
    const subject = this.language === 'it'
      ? `Richiesta informazioni: ${title}`
      : `Request information: ${title}`;

    return `mailto:${this.artistEmail}?subject=${encodeURIComponent(subject)}`;
  }
}
